var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"휴우, 일단 따돌린 것 같네요.","JPN":"ふぅ、一旦はまいたようですね。","ENG":"Whew, we ditched them for now.","TWN":"呼，算是把他們甩掉了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 군사기지를 벗어나지 못하는 한, 결국 잡히겠지만요.","JPN":"この軍事基地から離れない限り、どのみち捕まるのでしょうけど。","ENG":"But we'll get caught unless we get out of this military base.","TWN":"但只要沒逃出這個軍事基地，終究還是會被抓住的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 일단은 숨 좀 돌리기로 해요.","JPN":"ハハ、とりあえず一息つきましょうか。","ENG":"Hah hah. Let's take a breather for now.","TWN":"哈哈，先喘口氣吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"다이브하자마자 싸웠더니 제 속이 다 울렁거리네요.","JPN":"ダイブ直後に戦ったせいで、胸がムカムカします。","ENG":"My stomach is churning from having to fight right after we dived.","TWN":"竟然剛躍入就要打架，我的心臟都在砰砰跳呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......할 수 없죠. 저기 저 방으로 들어가요.","JPN":"……仕方ありませんね。向こうの部屋に入りましょう。","ENG":"Okay, let's enter that room over there.","TWN":"……沒辦法。去那邊的房間吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이런 상황에서 단둘만의 시츄에이션으로 유인하다니, 대담하시네요.","JPN":"こんな状況で二人っきりになろうだなんて、大胆ですね。","ENG":"You want to be alone with me in a situation like this? You're pretty bold.","TWN":"在這種情況下，居然還要製造兩人獨處的機會，妳真是大膽呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시끄러워요, 이 외설가!","JPN":"ちょっと黙ってください、このお調子者！","ENG":"Get your mind out of the gutter!","TWN":"吵死了，妳這變態！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런데 여긴 대체 어디일까요?","JPN":"ところで、ここはいったいどこでしょうね？","ENG":"By the way, where on earth are we?","TWN":"不過，這裡到底是哪裡呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자살에 가까운 고심도 다이브라고 해서 뭐가 나오든 놀라지 않으려고 했는데......","JPN":"命の保障がないほどの高深度ダイブということで、何が出現しても驚くまいと覚悟していたのですが……","ENG":"Since this high-depth Dive was all but suicidal, I readied myself for all possibilities.","TWN":"聽說是接近自殺的深度躍入，我想說無論出現什麼，我都不會被嚇到……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이면세계에 이런 곳이 있다는 이야기는 들은 적이 없네요.","JPN":"裏世界にこんな場所があるとは、聞いたことがありません。","ENG":"But I've never heard of a place like this in the Counterside.","TWN":"但我可從沒聽說過異界還有這種地方。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여긴 이면세계라기보단 멀쩡한 현실 세계잖아요?","JPN":"ここは裏世界というより、普通の現実世界じゃないですか？","ENG":"It looks more like it's in the Normalside than in the Counterside.","TWN":"這裡比起異界，更像正常的現實世界不是嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"설마 저희들, 그냥 장소만 이동한 건 아니겠죠?","JPN":"まさか私たち、ただ移動しただけなのでは？","ENG":"We didn't just move to a different place, did we?","TWN":"我們不會只是移動到了別的場所吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아뇨. 이런 시설은 우리 세계에 존재하지 않습니다.","JPN":"いいえ、こんな施設は私たちの世界には存在しません。","ENG":"No. Facilities like this don't exist in our world.","TWN":"不會。這種設施不存在於我們的世界。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"만일 있었다면 델타 세븐 정보과 소속인 제가 몰랐을 리 없어요.","JPN":"もし存在するなら、デルタセブン監査課所属の私が知らないわけありませんから。","ENG":"If it did, I would have known. I'm in Delta Seven's Intelligence Department.","TWN":"如果存在的話，身為第七三角洲部隊情報部的所屬人員，我不可能不知道。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 그렇게 확신할 수 있는 근거는요?","JPN":"ふーん、そう確信する根拠は？","ENG":"Hm, what makes you so sure?","TWN":"嗯，妳這麼確信的根據呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당연히 있죠. 여기, 계측기를 보세요.","JPN":"もちろんあります。計測器の……\\nここを見てください。","ENG":"Here, take a look at this meter.","TWN":"當然有。請看這個儀器。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 세계의 물질 구성 원소는 우리 몸을 이루는 것보다 양자 위상이 5단계 이상 차이나요.","JPN":"この世界の物質を構成する元素は、私たちの身体と比べて、量子位相が5段階以上離れているのです。","ENG":"Elements in this world are at a quantum phase that's at least 5 levels higher than those of our bodies.","TWN":"這個世界的物質構成元素與我們的身體相比，量子能量相差5級以上。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"다이브는 성공했습니다. 이곳은 절대 우리가 살던 세계가 아니에요.","JPN":"ダイブは成功しています。ここは決して私たちが暮らしていた世界ではありません。","ENG":"Our Dive has been successful. This is not part of our world.","TWN":"躍入成功了。這裡絕不是我們所生活的那個世界。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 양자 위상차 때문에 24시간 안에 우리 몸의 구성 원소가 완전히 파괴된다는 사실도 그대로겠네요.","JPN":"なので、量子位相が異なるせいで、私たちの体をなす元素が24時間以内に完全破壊されるという事実も変わりませんね。","ENG":"Then, the fact remains that our bodies will be completely destroyed in 24 hours because of that quantum phase difference.","TWN":"而由於量子能量差的關係，我們身體的構成元素將在24小時內完全被破壞，這個事實也不曾改變呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아...... 아쉬워라.","JPN":"はあ……残念。","ENG":"*Sigh...* How disappointing!","TWN":"哈啊……真可惜。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"멀쩡한 세상이면 이대로 눌러앉아서 여생을 편히 보낼 수 있지 않을까 잠깐 설렜는데......","JPN":"普通の世界なら、このままここで余生を楽に過ごせないかとちょっぴり期待したのに……","ENG":"For a moment, I hoped this was a normal world, so I could spend the rest of my life here peacefully...","TWN":"如果是正常世界的話，在這裡安度晚年也不錯，我還心動了一下……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"주시영 씨!","JPN":"シノンさん！","ENG":"Joo Shiyoung!","TWN":"周時雨小姐！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 농담이에요. 농담. 뭘 그렇게 무섭게 노려보세요.","JPN":"ハハ、冗談ですよ、冗談。そんなに睨みつけないでくださいよ。","ENG":"Hah hah. I was just kidding. I swear. Stop glaring at me like that.","TWN":"哈哈，開個玩笑啦，玩笑。妳的眼神變得很可怕耶。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이래봬도 카린 양의 델타 세븐에서 믿고 고용할 만큼 프로페셔널한 용병이랍니다.","JPN":"こう見えても、カリンさんのデルタセブンに雇われるほど、プロフェッショナルな傭兵ですからね。","ENG":"I may not look it, but I'm a mercenary professional enough to be hired by your organization.","TWN":"別看我這樣，我好歹也是個職業傭兵，足以被卡琳小姐的第七三角洲部隊信任和雇用。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"받은 만큼은 확실히 서비스 해 드려야죠, 받은 만큼은요.","JPN":"頂いた給料分はしっかり働きますよ、頂いた分はね。","ENG":"I'll do what I'm paid to do. That's a given.","TWN":"都拿了錢總得好好做事吧，不過拿多少做多少囉。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신 같은 용병에게 이런 말이 얼마나 의미가 있을지는 모르겠지만......","JPN":"あなたのような傭兵にこんな言葉が響くかわかりませんが……","ENG":"I don't know if it's even worth saying this to a mercenary like you,","TWN":"雖然不知道對妳這樣的傭兵說這些話有沒有意義……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우린 이 절망적인 상황의 마지막 남은 희망이에요.","JPN":"私たちはこの絶望的な状況に残された最後の希望です。","ENG":"but we're the last hope in this desperate situation.","TWN":"但我們是這個絕望的情況下最後的希望。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리가 성공하기만을 바라는 사람들이 <color=#ffd34c>아직</color> 많이 있다는 사실, 잊지 마세요.","JPN":"私たちの成功を願っている人が<color=#ffd34c>まだ</color>たくさんいるということ、忘れないでくださいね。","ENG":"Don't forget there are <color=#ffd34c>still</color> many people who want us to succeed.","TWN":"請不要忘記 ，<color=#ffd34c>仍有</color>很多人期盼著我們的成功。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 아직이라......","JPN":"ハハ、「まだ」か……","ENG":"Hah hah. Still, huh?","TWN":"哈哈，“仍有”嗎……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저희도 참 변변찮은 희망이네요.","JPN":"私たちって、ほんと頼りにならない希望ですね。","ENG":"So much hope for the situation.","TWN":"我們可真是個渺小的希望啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};